    unresolvedItems: [],
    gateResult: "not-run",
  };

  return {
    ...payload,
    ...overrides,
    crossStoryFindings:
      overrides.crossStoryFindings ?? payload.crossStoryFindings,
    architectureFindings:
      overrides.architectureFindings ?? payload.architectureFindings,
