BaselineEntry[];\\n  const current = await collectCurrentEntries();\\n  const baselineMap = new Map(baseline.map((entry) => [entry.path, entry.sha256]));\\n  const currentMap = new Map(current.map((entry) => [entry.path, entry.sha256]));\\n  const changedPaths = new Set<string>();\\n\\n  for (const [path, sha256] of currentMap) {\\n    if (baselineMap.get(path) !== sha256) {\\n      changedPaths.add(path);\\n    }\\n  }\\n\\n  for (const path of baselineMap.keys()) {\\n    if (!currentMap.has(path)) {\\n      changedPaths.add(path);\\n    }\\n  }\\n\\n  if (changedPaths.size > 0) {\\n    console.error(\\\"Test files changed after the captured red-phase baseline:\\\");\\n    for (const path of [...changedPaths].sort((left, right) =>\\n      left.localeCompare(right)\\n    )) {\\n      console.error(`- ${path}`);\\n    }\\n    process.exit(1);\\n  }\\n\\n  console.log(\\\"No test file changes detected since the captured baseline.\\\");\\n}\\n\\nmain().catch((error: unknown) => {\\n  console.error(\\n    error instanceof Error ? error.message : String(error)\\n  );\\n  process.exit(1);\\n});\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n./docs/spec-build/epics/01-claude-impl-cli-skill/artifacts/story-04/001-implementor.jsonl:129:{\"type\":\"item.started\",\"item\":{\"id\":\"item_72\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'bun run capture:test-baseline --force'\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\n./docs/spec-build/epics/01-claude-impl-cli-skill/artifacts/story-04/001-implementor.jsonl:130:{\"type\":\"item.completed\",\"item\":{\"id\":\"item_72\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc 'bun run capture:test-baseline --force'\",\"aggregated_output\":\"$ bun run scripts/capture-test-baseline.ts --force\\nCaptured test baseline at /Users/leemoore/code/liminal-spec/.test-tmp/green-verify/test-file-baseline.json\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n./docs/spec-build/epics/01-claude-