122	async function loadVerifierReports(
123	  verifierReportPaths: string[]
124	): Promise<{ results?: EpicVerifierResult[]; errors?: CliError[] }> {
125	  const collected: EpicVerifierResult[] = [];
126	
127	  for (const reportPath of verifierReportPaths) {
128	    const resolvedPath = resolve(reportPath);
129	    if (!(await pathExists(resolvedPath))) {
130	      return {
131	        errors: [
132	          blockedError(
133	            "INVALID_SPEC_PACK",
134	            `Verifier report was not found: ${resolvedPath}`
135	          ),
136	        ],
137	      };
138	    }
139	
140	    if (!(await pathReadable(resolvedPath))) {
141	      return {
142	        errors: [
143	          blockedError(
144	            "INVALID_SPEC_PACK",
145	            `Verifier report is not readable: ${resolvedPath}`
146	          ),
147	        ],
148	      };
149	    }
150	
151	    let content: string;
152	    try {
153	      content = await readTextFile(resolvedPath);
154	    } catch (error) {
155	      return {
156	        errors: [
157	          blockedError(
158	            "INVALID_SPEC_PACK",
159	            `Verifier report could not be read: ${resolvedPath}`,
160	            error instanceof Error ? error.message : String(error)
161	          ),
162	        ],
163	      };
164	    }
165	
166	    const parsed = parseVerifierReportContent(content);
167	    if (!parsed) {
168	      return {
169	        errors: [
170	          blockedError(
171	            "INVALID_SPEC_PACK",
172	            `Verifier report was not valid JSON for the epic verifier contract: ${resolvedPath}`
173	          ),
174	        ],
175	      };
176	    }
177	
178	    collected.push(...parsed);
179	  }
180	
181	  return {
182	    results: collected,
183	  };
184	}
