186	async function prepareSynthesisContext(input: {
187	  specPackRoot: string;
188	  verifierReportPaths: string[];
189	  configPath?: string;
190	}): Promise<PreparedSynthesisContext | { errors: CliError[] }> {
191	  const inspection = await inspectSpecPack(input.specPackRoot);
192	  if (inspection.status !== "ready") {
193	    return {
194	      errors: [
195	        blockedError(
196	          "INVALID_SPEC_PACK",
197	          "Spec-pack inspection must be ready before epic synthesis can start.",
198	          inspection.blockers.join("; ") || inspection.notes.join("; ")
199	        ),
200	      ],
201	    };
202	  }
203	
204	  const reportResolution = await loadVerifierReports(input.verifierReportPaths);
205	  if (reportResolution.errors || !reportResolution.results) {
206	    return {
207	      errors:
208	        reportResolution.errors ??
209	        [
210	          blockedError(
211	            "INVALID_SPEC_PACK",
212	            "Epic synthesis requires at least one verifier report."
213	          ),
214	        ],
215	    };
216	  }
217	
218	  const config = await loadRunConfig({
219	    specPackRoot: inspection.specPackRoot,
220	    configPath: input.configPath,
221	  });
222	  const gateResolution = await resolveVerificationGates({
223	    specPackRoot: inspection.specPackRoot,
224	  });
225	  if (gateResolution.status !== "ready" || !gateResolution.verificationGates) {
226	    return {
227	      errors: gateResolution.errors.length
228	        ? gateResolution.errors
229	        : [
230	            blockedError(
231	              "VERIFICATION_GATE_UNRESOLVED",
232	              "Verification gates must be resolved before epic synthesis can start."
233	            ),
234	          ],
235	    };
236	  }
237	
238	  return {
239	    specPackRoot: inspection.specPackRoot,
240	    provider: providerForHarness(config.epic_synthesizer.secondary_harness),
241	    model: config.epic_synthesizer.model,
242	    reasoningEffort: config.epic_synthesizer.reasoning_effort,
243	    verifierReportPaths: input.verifierReportPaths.map((path) => resolve(path)),
244	    verifierResults: reportResolution.results,
245	    gateCommands: {
246	      story: gateResolution.verificationGates.storyGate,
247	      epic: gateResolution.verificationGates.epicGate,
248	    },
249	    paths: {
